             <td align="left" class="content" style="text-align: center;" width="308">
              <a class="image-link" href="https://substack.com/redirect/10047717-36fd-4aee-b8ef-d1699f3829c4?r=9p0gt" rel="" style="align-items: center; border: none; display: block; flex-direction: column; height: auto; margin: 0; padding: 0; position: relative; text-decoration: none; width: auto;" target="_blank">
               <img alt="" class="" data-attrs='{"src":"https://bucketeer-e05bbc84-baa3-437e-9518-adb32be77984.s3.amazonaws.com/public/images/35c8cae6-754f-4683-b849-f6fadb140a52_308x659.png","fullscreen":null,"imageSize":null,"height":659,"width":308,"resizeWidth":null,"bytes":null,"alt":null,"title":null,"type":null,"href":null,"belowTheFold":true,"internalRedirect":null}' height="659" src="https://substackcdn.com/image/fetch/w_308,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fbucketeer-e05bbc84-baa3-437e-9518-adb32be77984.s3.amazonaws.com%2Fpublic%2Fimages%2F35c8cae6-754f-4683-b849-f6fadb140a52_308x659.png" style="-ms-interpolation-mode: bicubic; border: none !important; display: block; height: auto; margin: 0 auto; margin-bottom: 0; max-width: 100% !important; vertical-align: middle; width: auto !important;" width="308"/>
              </a>
